import{_ as e,o as t,c as l,a2 as r}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"1987年巴菲特致股东的信核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1987年/核心总结.md","filePath":"01_letters/1987年/核心总结.md"}'),o={name:"01_letters/1987年/核心总结.md"};function i(n,a,h,s,p,d){return t(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="_1987年巴菲特致股东的信核心总结" tabindex="-1">1987年巴菲特致股东的信核心总结 <a class="header-anchor" href="#_1987年巴菲特致股东的信核心总结" aria-label="Permalink to &quot;1987年巴菲特致股东的信核心总结&quot;">​</a></h1><h2 id="简要导读" tabindex="-1">简要导读 <a class="header-anchor" href="#简要导读" aria-label="Permalink to &quot;简要导读&quot;">​</a></h2><p>1987年股灾之后，巴菲特写下这封信，再次把格雷厄姆的&quot;市场先生&quot;故事讲给大家听，讲得清清楚楚，现在读依然振聋发聩。同时巴菲特也把他怎么看待我们持有的好企业，讲得明明白白，这封信值得每个投资者收藏。文末可下载英文原版PDF。</p><h2 id="一、真正卓越的回报-来自不变-不是变化" tabindex="-1">一、真正卓越的回报，来自不变，不是变化 <a class="header-anchor" href="#一、真正卓越的回报-来自不变-不是变化" aria-label="Permalink to &quot;一、真正卓越的回报，来自不变，不是变化&quot;">​</a></h2><p>巴菲特说，剧烈变化和超额回报通常不搭，大多数持续高回报，来自一直做你本来就擅长做的事，不要瞎折腾，找那些听起来性感但你根本不懂的新东西。</p><p>《财富》统计，过去十年，连续十年平均ROE超过20%，每年最低不低于15%，一千家大公司只有二十五家，大部分都是平淡无奇行业，卖普通商品，很多不性感，但就是能持续赚钱，就是把简单事情做到极致，巴菲特说伯克希尔也一样，我们经理人就是把普通事情做到极致，我们拿到超额回报。</p><p>例子：94岁B夫人还在干，每天上班，依然不断增长，喜诗糖果，就是一块巧克力，几十年做好，现在依然稳定盈利，水牛城新闻坚持高新闻比例，渗透率全美第一，这就是把简单事做到极致。</p><h2 id="二、保险行业-我们和别人不一样" tabindex="-1">二、保险行业：我们和别人不一样 <a class="header-anchor" href="#二、保险行业-我们和别人不一样" aria-label="Permalink to &quot;二、保险行业：我们和别人不一样&quot;">​</a></h2><p>巴菲特说，保险就是大宗商品生意，只有短缺才能赚钱，短缺了大家忍不住扩产能，所以赚钱之后很快又变成亏钱，这就是行业宿命，我们和别人不一样：</p><ol><li>我们靠财务实力差异化，别人不敢接大单我们敢接，只有真出事了，买家才知道谁真能赔，那时候我们优势就出来了，所以我们就是备用产能，别人不敢接我们接，我们不追求规模，价格不对我们不接，价格对我们才接，对行业对买家都好。</li><li>我们对规模完全无所谓，我们可以做五倍也可以做五分之一，我们不关心市场份额，只关心价格对不对，这个行业大多数做不到，我们能做到，所以我们长期能赚钱。</li></ol><p>结论：1987年是行业好年，保费增长放缓，未来综合成本率会慢慢上升，但是我们因为浮存金增长，利润还会涨。</p><h2 id="三、巴菲特投资哲学-市场先生就是你的仆人-不是你的主人" tabindex="-1">三、巴菲特投资哲学：市场先生就是你的仆人，不是你的主人 <a class="header-anchor" href="#三、巴菲特投资哲学-市场先生就是你的仆人-不是你的主人" aria-label="Permalink to &quot;三、巴菲特投资哲学：市场先生就是你的仆人，不是你的主人&quot;">​</a></h2><p>巴菲特再次讲了格雷厄姆市场先生寓言，太经典了，我转述一遍：</p><ul><li>你和市场先生合伙做生意，他每天给你报价，要买你的股份也要卖给你他的股份，他情绪不稳定，开心的时候报很高，不开心报很低，你完全可以不理他，利用他价格，不要被他影响。</li><li>如果你被他影响，你乱卖乱买，你就完蛋了，因为他本来就是疯子，你跟着疯，当然完蛋。</li><li>&quot;短期来看，市场是投票机，长期来看，市场是称重机&quot;，最后企业怎么样，价值一定会体现，哪怕晚一点，没关系，便宜的时候你还能多买。</li></ul><p>巴菲特说，我们买股票就是买生意，我们买控股 minority 都一样，我们就是看 business 内在价值，不满意我们不卖，满意我们拿着，我们三大重仓首都城市、GEICO、华盛顿邮报，我们永远不卖，哪怕高估也不卖，就像我们不卖喜诗水牛城新闻一样，我们就是长期持有好生意。</p><h2 id="四、股灾之后-你慌不慌-巴菲特说什么" tabindex="-1">四、股灾之后，你慌不慌？巴菲特说什么？ <a class="header-anchor" href="#四、股灾之后-你慌不慌-巴菲特说什么" aria-label="Permalink to &quot;四、股灾之后，你慌不慌？巴菲特说什么？&quot;">​</a></h2><p>1987年十月股灾，很多大机构搞什么投资组合保险，价格跌一点就自动卖，所以越跌越卖，巴菲特说，这种行为，波动率变大，反而给真正投资者更好机会，因为价格跌了，你能买到更便宜，你只有被逼卖的时候才会受伤，你不用杠杆，不借钱，你怕什么？跌了反而有机会。</p><p>巴菲特说，我们现在没买到多少，因为涨回去太快，但是未来市场先生肯定还给我们机会，我们等着。</p><h2 id="五、核心启示" tabindex="-1">五、核心启示 <a class="header-anchor" href="#五、核心启示" aria-label="Permalink to &quot;五、核心启示&quot;">​</a></h2><ol><li>你不需要天天交易，不需要追热点，好企业拿着不动，比换来换去赚得多，很多人觉得不交易无聊，长期看无聊给你赚大钱，刺激给你亏大钱。</li><li>市场先生就是来给你送钱的，不是来给你指路的，你利用他价格，不要被他牵着走。</li><li>卓越回报来自把简单事情做到极致，不是天天折腾，找新东西，你本来就做得好的事情，坚持做，做到最好，就是复利。</li></ol><hr><blockquote><p>📎 <strong>文末小惊喜</strong>：可点击下载<a href="Chairman&#39;s%20Letter%20-%201987.pdf">巴菲特1987年股东信原件PDF</a>，原汁原味阅读英文原文。</p></blockquote>',22)])])}const u=e(o,[["render",i]]);export{c as __pageData,u as default};
